import{_ as a,a as i,b as t}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as l,o,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Автентифікація та керування пристроями входу","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Safety/authentication-and-login-devices.md","filePath":"uk-UA/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),c={name:"uk-UA/Safety/authentication-and-login-devices.md"};function d(p,e,s,h,u,m){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="автентифікація-та-керування-пристроями-входу" tabindex="-1">Автентифікація та керування пристроями входу <a class="header-anchor" href="#автентифікація-та-керування-пристроями-входу" aria-label="Permalink to &quot;Автентифікація та керування пристроями входу&quot;">​</a></h1><p><code>Authentication Management</code> і <code>Login Device Management</code> захищають адмін-панель ImgBed, публічну сторінку завантаження та WebDAV-доступ.</p><p>На цій сторінці можна налаштувати облікові дані доступу, переглянути пристрої, що входили в систему, і за потреби відкликати старі сесії.</p><h2 id="де-це-налаштовується" tabindex="-1">Де це налаштовується <a class="header-anchor" href="#де-це-налаштовується" aria-label="Permalink to &quot;Де це налаштовується&quot;">​</a></h2><p>Відкрийте адмін-панель і перейдіть до:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>На сторінці є дві основні області:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+a+'" alt="Керування автентифікацією" loading="lazy"></p><h2 id="для-чого-потрібен-authentication-management" tabindex="-1">Для чого потрібен Authentication Management <a class="header-anchor" href="#для-чого-потрібен-authentication-management" aria-label="Permalink to &quot;Для чого потрібен Authentication Management&quot;">​</a></h2><p>Authentication Management зберігає облікові дані доступу.</p><p>Є два типи:</p><ul><li>автентифікація для користувацької сторони;</li><li>автентифікація для адмін-сторони.</li></ul><h2 id="автентифікація-користувацькоі-сторони" tabindex="-1">Автентифікація користувацької сторони <a class="header-anchor" href="#автентифікація-користувацькоі-сторони" aria-label="Permalink to &quot;Автентифікація користувацької сторони&quot;">​</a></h2><p>Автентифікація користувацької сторони — це пароль для завантаження.</p><p>Після встановлення пароля звичайні відвідувачі мають ввести його перед використанням сторінки завантаження. Це корисно, якщо ви не хочете відкривати публічну сторінку завантаження для всіх.</p><p><img src="'+i+'" alt="Сторінка входу користувача" loading="lazy"></p><h3 id="налаштування-пароля-завантаження" tabindex="-1">Налаштування пароля завантаження <a class="header-anchor" href="#налаштування-пароля-завантаження" aria-label="Permalink to &quot;Налаштування пароля завантаження&quot;">​</a></h3><p>Коли пароль завантаження налаштовано:</p><ul><li>відвідувачі мають ввести пароль перед використанням сторінки завантаження;</li><li>завантаження доступне лише після прийняття пароля;</li><li>якщо ввімкнені сесії пристроїв користувацької сторони, ImgBed записує цей пристрій.</li></ul><p>Зміна пароля завантаження робить старі користувацькі сесії недійсними. Відвідувачам потрібно буде ввести новий пароль.</p><h2 id="автентифікація-адмін-сторони" tabindex="-1">Автентифікація адмін-сторони <a class="header-anchor" href="#автентифікація-адмін-сторони" aria-label="Permalink to &quot;Автентифікація адмін-сторони&quot;">​</a></h2><p>Автентифікація адмін-сторони використовує ім&#39;я адміністратора й пароль.</p><p>Вона захищає адмін-панель. Для production-сайту її варто завжди налаштовувати.</p><p><img src="'+t+'" alt="Сторінка входу адміністратора" loading="lazy"></p><h3 id="налаштування-облікових-даних-адміністратора" tabindex="-1">Налаштування облікових даних адміністратора <a class="header-anchor" href="#налаштування-облікових-даних-адміністратора" aria-label="Permalink to &quot;Налаштування облікових даних адміністратора&quot;">​</a></h3><p>Коли ім&#39;я адміністратора й пароль налаштовані:</p><ul><li>відкриття адмін-панелі потребує входу;</li><li>успішний вхід створює запис admin device;</li><li>у Login Device Management можна переглядати, чистити або примусово виводити пристрої офлайн.</li></ul><p>Зміна імені адміністратора або пароля робить старі admin sessions недійсними. Потрібно буде увійти знову.</p><h2 id="для-чого-потрібен-login-device-management" tabindex="-1">Для чого потрібен Login Device Management <a class="header-anchor" href="#для-чого-потрібен-login-device-management" aria-label="Permalink to &quot;Для чого потрібен Login Device Management&quot;">​</a></h2><p>Login Device Management показує пристрої, які входили в систему.</p><p>Він допомагає перевірити:</p><ul><li>які пристрої відкривали адмін-панель;</li><li>які пристрої відкривали користувацьку сторінку завантаження;</li><li>які WebDAV-клієнти підключалися;</li><li>чи сесія пристрою ще дійсна;</li><li>чи потрібно примусово вивести старі пристрої офлайн.</li></ul><p>На сторінці є три вкладки:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="глобальна-безпека-cookie" tabindex="-1">Глобальна безпека cookie <a class="header-anchor" href="#глобальна-безпека-cookie" aria-label="Permalink to &quot;Глобальна безпека cookie&quot;">​</a></h2><p>У верхній частині Login Device Management можна налаштувати глобальну поведінку cookie.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>Визначає, скільки днів користувацький вхід може залишатися активним.</p><p>Наприклад, якщо встановити 14 днів, відвідувачам зазвичай не потрібно повторно вводити пароль завантаження протягом 14 днів.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>Визначає, скільки днів вхід адміністратора може залишатися активним.</p><p>Наприклад, якщо встановити 14 днів, адміністраторам зазвичай не потрібно повторно входити протягом 14 днів.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Коли Secure mode увімкнений, браузери надсилають login cookies тільки через HTTPS.</p><p>Увімкніть його для production-сайтів із HTTPS. Не вмикайте для локального HTTP-тестування, інакше можна отримати поведінку на кшталт &quot;вхід успішний, але після оновлення сторінки мене викидає&quot;.</p><h2 id="пристроі-входу-адміністратора" tabindex="-1">Пристрої входу адміністратора <a class="header-anchor" href="#пристроі-входу-адміністратора" aria-label="Permalink to &quot;Пристрої входу адміністратора&quot;">​</a></h2><p>Вкладка Admin показує пристрої, які входили в адмін-панель.</p><p>Записи пристроїв з&#39;являються тільки після налаштування admin credentials і входу в адмін-панель через форму логіну.</p><p>Картка пристрою може показувати:</p><ul><li>інформацію про пристрій і браузер;</li><li>IP першого входу;</li><li>IP останньої активності;</li><li>час входу;</li><li>час останньої активності;</li><li>час завершення сесії;</li><li>поточний статус.</li></ul><p>Якщо бачите незнайомий пристрій, використайте <code>Force Offline</code>, щоб зробити його сесію недійсною.</p><h2 id="очищення-старих-пристроів" tabindex="-1">Очищення старих пристроїв <a class="header-anchor" href="#очищення-старих-пристроів" aria-label="Permalink to &quot;Очищення старих пристроїв&quot;">​</a></h2><p><code>Clean Up Old Devices</code> масово видаляє старі записи входу в поточній вкладці.</p><p>Використовуйте це, якщо підозрюєте, що старі сесії на інших пристроях усе ще можуть бути активними.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> робить недійсною одну сесію пристрою.</p><p>Після примусового виведення пристрою офлайн:</p><ul><li>admin devices мають увійти знову;</li><li>пристрої користувацької сторони мають знову ввести пароль завантаження;</li><li>WebDAV-клієнти мають пройти автентифікацію ще раз.</li></ul><p>Прострочені або недійсні пристрої також можна видаляти.</p><h2 id="вихід-із-поточного-пристрою" tabindex="-1">Вихід із поточного пристрою <a class="header-anchor" href="#вихід-із-поточного-пристрою" aria-label="Permalink to &quot;Вихід із поточного пристрою&quot;">​</a></h2><p>Картка поточного пристрою позначена як <code>Current Device</code>.</p><p>Після виходу з поточного пристрою:</p><ul><li>поточна admin session завершується;</li><li>поточна user-side session завершується.</li></ul><p>Щоб продовжити користуватися відповідною областю, потрібно увійти знову.</p>',65)])])}const k=l(c,[["render",d]]);export{b as __pageData,k as default};
